#include <stdio.h>
#include <stdlib.h>
#include <string.h>
int main()
{
char input[1000000];
scanf("%s",&input);
getchar();
int length=strlen(input),letter=length-1,numofzeroes=0,caseid;

if((length+1)%2==0)
caseid=0;
else
caseid=1;

while(input[letter]=='0'){
letter--;
numofzeroes++;
}

int done=0,front=0,back=letter;
while(done==0){

//printf("%d.%c %d.%c\n",front,input[front],back,input[back]);

if(input[front]!=input[back]){
done=1;
}
else if((length-numofzeroes)==1){
done=2;
}
else{
if(front==(((length-numofzeroes-caseid)/2)-(1-caseid))){
done=2;
}
front++;
back--;
}
}

if(done==2)
printf("YES");
else
printf("NO");

}

